    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setIsLoading(true);

        const form = e.target as HTMLFormElement;
        const passwordInput = form.elements.namedItem('password') as HTMLInputElement;
        const rawEmail = email;
