export function LoginPage({ onLogin, onNavigateToRegister, externalError, clearExternalError, initialRole, onGoBack, systemLogoUrl }: LoginPageProps): React.ReactNode {
    const [role, setRole] = React.useState<Role>(initialRole);
    const [isLoading, setIsLoading] = React.useState(false);
    const [error, setError] = React.useState('');
    const [showAcademyNotFound, setShowAcademyNotFound] = React.useState(false);
    const [showConfigError, setShowConfigError] = React.useState(false);

    React.useEffect(() => {
        setRole(initialRole);
    }, [initialRole]);

    React.useEffect(() => {
        if (externalError) {
            setError(externalError);
        }
    }, [externalError]);

    const handleSetError = (msg: string) => {
        clearExternalError();
        setError(msg);
    };

    const handleRoleChange = (newRole: Role) => {
        setRole(newRole);
        setError('');
        clearExternalError();
    };

    const nonAdminLoginProps = { setIsLoading, setError: handleSetError, onLogin, setShowConfigError };

    return (
        <>
        {showConfigError && <AuthErrorModal onClose={() => { setShowConfigError(false); setIsLoading(false); }} />}

        <AuthLayout title="Welcome Back!" subtitle="Please sign in to continue" onBack={onGoBack} systemLogoUrl={systemLogoUrl}>
            <AuthCard>
                <RoleSwitcher activeRole={role} onRoleChange={handleRoleChange} />

                {role === 'academy' && <AcademyLoginForm setIsLoading={setIsLoading} setError={handleSetError} onLoginFailed={() => setShowAcademyNotFound(true)} onLogin={onLogin} />}
                {role === 'student' && <StudentLoginForm {...nonAdminLoginProps} />}
                {role === 'staff' && <StaffLoginForm {...nonAdminLoginProps} />}

                {error && <p className="text-red-500 text-sm text-center mt-4 font-semibold">{error}</p>}

                {isLoading && (
                    <div className="absolute inset-0 bg-white/50 dark:bg-gray-800/50 flex justify-center items-center rounded-2xl z-10">
                        <LoadingSpinner />
                    </div>
                )}
            </AuthCard>

            <div className="text-center mt-6 space-y-2">
                {role === 'academy' && (
                    <p className="text-sm text-gray-600 dark:text-gray-300">
                        Don't have an account?{' '}
                        <button onClick={onNavigateToRegister} className="font-medium text-indigo-600 dark:text-indigo-400 hover:underline">
                            Register here
                        </button>
                    </p>
                )}
            </div>

            {showAcademyNotFound && (
                <AcademyLoginFailedPopup 
                    onCancel={() => setShowAcademyNotFound(false)}
                    onRegister={() => {
                        setShowAcademyNotFound(false);
                        onNavigateToRegister();
                    }}
                />
            )}
        </AuthLayout>
        </>
    );
}

import React, { useState, useRef, useEffect } from 'react';
import { ChevronDownIcon } from './icons/ChevronDownIcon';
import { CheckIcon } from './icons/CheckIcon';

interface DropdownOption {
    value: string;
    label: string;
}

interface CustomDropdownProps {
    options: DropdownOption[];
    selectedValue: string | null;
    onSelect: (value: string) => void;
    placeholder?: string;
    label?: string;
}

export function CustomDropdown({ options, selectedValue, onSelect, placeholder = "Select...", label }: CustomDropdownProps) {
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    const selectedOption = options.find(opt => opt.value === selectedValue);

    const handleSelectOption = (value: string) => {
        onSelect(value);
        setIsOpen(false);
    };

    return (
        <div className="w-full" ref={dropdownRef}>
            {label && <label className="block text-gray-500 dark:text-gray-400 text-sm font-medium mb-2">{label}</label>}
            <button
                type="button"
                onClick={() => setIsOpen(!isOpen)}
                className="w-full flex items-center justify-between p-3 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-lg text-left focus:outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm transition-all"
                aria-haspopup="listbox"
                aria-expanded={isOpen}
            >
                <span className={`truncate ${selectedValue ? 'text-gray-800 dark:text-gray-100' : 'text-gray-500 dark:text-gray-400'}`}>
                    {selectedOption?.label || placeholder}
                </span>
                <ChevronDownIcon className={`w-5 h-5 text-gray-400 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
            </button>

            {/* Changed from absolute to relative/inline flow to give options 'there itself' */}
            {isOpen && (
                <div
                    className="mt-2 w-full bg-gray-50 dark:bg-gray-800/50 shadow-inner rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 animate-fade-in"
                >
                    <ul role="listbox" className="max-h-60 overflow-y-auto">
                        {options.length > 0 ? (
                            options.map(option => (
                                <li
                                    key={option.value}
                                    onClick={() => handleSelectOption(option.value)}
                                    className={`px-4 py-3 text-sm cursor-pointer hover:bg-white dark:hover:bg-gray-700 border-b border-gray-100 dark:border-gray-700 last:border-0 flex justify-between items-center ${selectedValue === option.value ? 'bg-white dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 font-bold' : 'text-gray-700 dark:text-gray-200'}`}
                                    role="option"
                                    aria-selected={selectedValue === option.value}
                                >
                                    <span>{option.label}</span>
                                    {selectedValue === option.value && (
                                        <CheckIcon className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
                                    )}
                                </li>
                            ))
                        ) : (
                            <li className="px-4 py-3 text-gray-500 text-sm">No options available</li>
                        )}
                    </ul>
                </div>
            )}
        </div>
    );
}

