            return 'role-selection';
        }
        return 'onboarding';
    });
    const [loginPageRole, setLoginPageRole] = useState<Role>('academy');
    const [pageParams, setPageParams] = useState<{[key: string]: any}>({});
    const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isNavOpen, setIsNavOpen] = useState(false);
    const [authError, setAuthError] = useState<string | null>(null);
    const [systemLogoUrl, setSystemLogoUrl] = useState<string | null>(null);

    // Data state
    const [academy, setAcademy] = useState<Academy | null>(null);
    const [batches, setBatches] = useState<Batch[]>([]);
    const [students, setStudents] = useState<Student[]>([]);
    const [staff, setStaff] = useState<Staff[]>([]);
    const [staffAttendance, setStaffAttendance] = useState<StaffAttendance[]>([]);
    const [feeCollections, setFeeCollections] = useState<FeeCollection[]>([]);
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [exams, setExams] = useState<Exam[]>([]);
    const [enquiries, setEnquiries] = useState<Enquiry[]>([]);
    const [studyMaterials, setStudyMaterials] = useState<StudyMaterial[]>([]);
    const [homework, setHomework] = useState<Homework[]>([]);
    const [quizzes, setQuizzes] = useState<Quiz[]>([]);
    const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
    const [tasks, setTasks] = useState<Task[]>([]);
    const [notices, setNotices] = useState<Notice[]>([]);
    const [transportRoutes, setTransportRoutes] = useState<TransportRoute[]>([]);
    const [salaryPayments, setSalaryPayments] = useState<SalaryPayment[]>([]); 

    // Page-specific state
    const [selectedBatchId, setSelectedBatchId] = useState<string | null>(null);
    const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
    const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
    const [selectedExamId, setSelectedExamId] = useState<string | null>(null);
    const [selectedEnquiryId, setSelectedEnquiryId] = useState<string | null>(null);
    const [studentListFilter, setStudentListFilter] = useState('all');

    // UI State
    const [connectionError, setConnectionError] = useState<string | null>(null);
    const [isOffline, setIsOffline] = useState(!navigator.onLine);
    const [showConsent, setShowConsent] = useState(!localStorage.getItem('dataConsentAccepted'));
    const [showDevPopup, setShowDevPopup] = useState<string | null>(null);
    const [imageToView, setImageToView] = useState<string | null>(null);
    const [isChatbotOpen, setIsChatbotOpen] = useState(false);

    useEffect(() => {
        const initializeApp = async () => {
            if (Capacitor.isNativePlatform()) {
                await StatusBar.setStyle({ style: Style.Light });
                await CapSplashScreen.hide();
            }
        };
        initializeApp();
    }, []);

    useEffect(() => {
        if (isPlaceholderConfig) return;
        const unsubConfig = onSnapshot(doc(db, 'system_config', 'main'), (docSnap) => {
            if (docSnap.exists()) {
                setSystemLogoUrl(docSnap.data().logoUrl || null);
            }
        });
        return () => unsubConfig();
    }, []);

    const isDemoMode = (currentUser?.role === 'admin' && currentUser.data.id === 'demo-academy-id') ||
        ((currentUser?.role === 'student' || currentUser?.role === 'staff') && currentUser.academyId === 'DEMO');

    useEffect(() => {
        if (theme === 'dark') {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [theme]);

    const handleToggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

    const handleNavigate = (page: string, params?: {[key: string]: any}) => {
        setPageParams(params || {});
        setPage(page);
    };

    useEffect(() => {
        const handleOnline = () => setIsOffline(false);
        const handleOffline = () => setIsOffline(true);
        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);
        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    useEffect(() => {
        if (isPlaceholderConfig) {
            setIsLoading(false);
            if (!localStorage.getItem('onboardingCompleted')) setPage('onboarding');
            else if (localStorage.getItem('lastSelectedRole')) {
                 setLoginPageRole(localStorage.getItem('lastSelectedRole') as Role);
                 setPage('login');
            } else setPage('role-selection');
            return;
        }

        const unsubscribe = auth.onAuthStateChanged(async (user: firebase.User | null) => {
             try {
                if (user) {
                    if (user.isAnonymous) return;
                    const userDocRef = doc(db, "users", user.uid);
                    const userDocSnap = await getDoc(userDocRef);
                    if (userDocSnap.exists()) {
                        const userData = userDocSnap.data();
                        if (userData.role === 'admin' && userData.academyId) {
                            const academyDocRef = doc(db, "academies", userData.academyId);
                            const academyDocSnap = await getDoc(academyDocRef);
                            if (academyDocSnap.exists()) {
                                const academyData = { id: academyDocSnap.id, ...academyDocSnap.data() } as Academy;
                                setAcademy(academyData);
                                setCurrentUser({ role: 'admin', data: academyData });
                                setPage('dashboard');
                            } else {
                                setAuthError("Your academy data is missing.");
                                setPage('complete-registration');
                            }
                        } else {
                            setAuthError("Account error.");
                            await auth.signOut();
                        }
                    } else {
                         setPage('complete-registration');
                    }
                } else {
                    setCurrentUser(null);
                    setAcademy(null);
                    if (localStorage.getItem('onboardingCompleted')) {
                         setPage(localStorage.getItem('lastSelectedRole') ? 'login' : 'role-selection');
                    } else {
                        setPage('onboarding');
                    }
                }
            } catch (error) {
                console.error("Auth error", error);
            } finally {
                setIsLoading(false);
            }
        });
        return () => unsubscribe();
    }, []);

    useEffect(() => {
        if (!currentUser || isPlaceholderConfig || isDemoMode) {
            if (isDemoMode) {
                setAcademy({ id: 'demo', academyId: 'DEMO', name: 'Demo Academy', adminUid: 'demo', adminEmail: 'demo@test.com', status: 'active', subscriptionStatus: 'active' });
                setBatches(demoBatches);
                setStudents(demoStudents);
                setStaff(demoStaff);
                setTransactions(demoTransactions);
                setEnquiries(demoEnquiries);
                setTransportRoutes(demoTransportRoutes);
                setStaffAttendance(demoStaffAttendance);
            }
            return;
        };

        const academyId = (currentUser.role === 'admin') ? currentUser.data.id : currentUser.academyId;
        if (!academyId) return;

        const unsubscribers: (() => void)[] = [];

        const academyDocRef = doc(db, 'academies', academyId);
        unsubscribers.push(onSnapshot(academyDocRef, (docSnap) => {
            if (docSnap.exists()) {
                setAcademy({ id: docSnap.id, ...docSnap.data() } as Academy);
            }
        }));

        const collections = ['batches', 'students', 'staff', 'fees', 'transactions', 'exams', 'enquiries', 'studyMaterial', 'homework', 'quizzes', 'leaveRequests', 'tasks', 'notices', 'transportRoutes', 'staffAttendance', 'salaryPayments'];

        const setters: any = {
            batches: setBatches, students: setStudents, staff: setStaff, fees: setFeeCollections,
            transactions: setTransactions, exams: setExams, enquiries: setEnquiries, studyMaterial: setStudyMaterials,
            homework: setHomework, quizzes: setQuizzes, leaveRequests: setLeaveRequests, tasks: setTasks,
            notices: setNotices, transportRoutes: setTransportRoutes, staffAttendance: setStaffAttendance, salaryPayments: setSalaryPayments
        };

        collections.forEach(coll => {
             const collRef = collection(db, `academies/${academyId}/${coll}`);
             unsubscribers.push(onSnapshot(collRef, (snap) => {
                 setters[coll](snap.docs.map(d => ({ id: d.id, ...d.data() })));
             }));
        });

        return () => unsubscribers.forEach(u => u());
    }, [currentUser, isDemoMode]);

    const handleLogin = (user: CurrentUser) => {
        setAuthError(null);
        setCurrentUser(user);
        if (user.role === 'admin') setAcademy(user.data);
        setPage('dashboard');
    };

    const handleLogout = async () => {
        setIsNavOpen(false);
        if(!isDemoMode) await auth.signOut();
        setCurrentUser(null);
        setAcademy(null);
        localStorage.removeItem('lastSelectedRole');
        setPage('role-selection');
    };

    const handleShowDevPopup = (name: string) => setShowDevPopup(name);

    const handleToggleStudentStatus = async (studentId: string) => {
        if (isDemoMode) {
             setStudents(prev => prev.map(s => s.id === studentId ? { ...s, isActive: !s.isActive } : s));
             return;
        }
        if (!academy) return;
        const student = students.find(s => s.id === studentId);
        if (!student) return;
        try {
            await updateDoc(doc(db, `academies/${academy.id}/students`, studentId), {
                isActive: !student.isActive
            });
        } catch (error) {
            console.error("Error toggling student status:", error);
        }
    };

    const handleBulkSaveStudents = async (studentsData: Omit<Student, 'id' | 'isActive'>[]) => {
        if (!academy || isDemoMode) throw new Error("Cannot save in demo mode.");
        const chunkSize = 400;
        for (let i = 0; i < studentsData.length; i += chunkSize) {
            const chunk = studentsData.slice(i, i + chunkSize);
            const batch = writeBatch(db);
            chunk.forEach(studentData => {
                const studentRef = doc(collection(db, `academies/${academy.id}/students`));
                batch.set(studentRef, { ...studentData, isActive: true });
                studentData.batches.forEach(bName => {
                    const batchObj = batches.find(b => b.name.trim().toLowerCase() === bName.trim().toLowerCase());
                    if (batchObj) batch.update(doc(db, `academies/${academy.id}/batches`, batchObj.id), { currentStudents: increment(1) });
                });
            });
            await batch.commit();
        }
    };

    const handleSaveSchedule = async (date: string, batchId: string, scheduleItems: ScheduleItem[]) => {
        if (!academy || isDemoMode) return;
        try {
            const scheduleRef = doc(db, `academies/${academy.id}/schedules`, date);
            await setDoc(scheduleRef, { [batchId]: scheduleItems }, { merge: true });
        } catch (error) {
            console.error("Error saving schedule:", error);
            throw new Error("Failed to save schedule. Please check your internet connection.");
        }
    };

    const handleSubscribe = async (plan: 'monthly' | 'quarterly' | 'yearly', months: number, paymentDetails: { paymentId: string; amount: number }) => {
        if (!academy || isDemoMode) return;

        const academyRef = doc(db, 'academies', academy.id);
        const now = new Date();

        // Calculate new end date. If already active, extend from end date. Otherwise extend from now.
        let startDate = now;
        if (academy.subscriptionStatus === 'active' && academy.subscriptionEndsAt) {
            const currentEndDate = academy.subscriptionEndsAt.toDate();
            if (currentEndDate > now) {
                startDate = currentEndDate;
            }
        }

        const newEnd = new Date(startDate);
        newEnd.setMonth(newEnd.getMonth() + months);

        try {
            await updateDoc(academyRef, {
                plan: plan,
                subscriptionStatus: 'active',
                subscriptionEndsAt: Timestamp.fromDate(newEnd),
                lastPaymentId: paymentDetails.paymentId
            });

            // Log as transaction (Optional but recommended)
            const txRef = doc(collection(db, `academies/${academy.id}/transactions`));
            await setDoc(txRef, {
                type: 'Expense',
                category: 'Subscription',
                amount: paymentDetails.amount / 100, // Razorpay amount is in paise
                paymentMethod: 'UPI', // Simplification
                description: `OptiLearn ${plan} plan renewal`,
                date: serverTimestamp(),
                createdAt: serverTimestamp()
            });

            alert("Subscription updated successfully! Welcome to the " + plan + " plan.");
        } catch (error) {
            console.error("Failed to update subscription after payment:", error);
            throw error;
        }
    };

    const renderPage = () => {
        const student = currentUser?.role === 'student' ? currentUser.data : null;
        const academyId = academy?.id || '';

        switch (page) {
            case 'dashboard':
                if (currentUser?.role === 'admin') return <Dashboard onNavigate={setPage} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                if (currentUser?.role === 'student') return <StudentDashboardPage student={currentUser.data} academy={academy!} feeCollections={feeCollections} batches={batches} onNavigate={setPage} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                if (currentUser?.role === 'staff') return <StaffDashboardPage onNavigate={setPage} academy={academy!} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                return null;

            // Student Management
            case 'student-options': return <StudentOptionsPage onBack={() => setPage('dashboard')} onNavigate={setPage} isStaffView={currentUser?.role === 'staff'} onShowDevPopup={handleShowDevPopup} />;
            case 'active-students': return <ActiveStudentsPage onBack={() => setPage('student-options')} students={students} batches={batches} onToggleStudentStatus={handleToggleStudentStatus} onEditStudent={(id) => { setSelectedStudentId(id); setPage('edit-student'); }} onViewStudent={(id) => { setSelectedStudentId(id); setPage('student-details')}} initialFilter={studentListFilter} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined}/>;
            case 'inactive-students': return <InactiveStudentsPage onBack={() => setPage('student-options')} students={students} batches={batches} onToggleStudentStatus={handleToggleStudentStatus} />;
            case 'bulk-upload-students': return <BulkUploadPage onBack={() => setPage('student-options')} onSave={handleBulkSaveStudents} batches={batches} isDemoMode={isDemoMode || false} />;
            case 'new-student': return <NewStudentPage onBack={() => setPage('student-options')} onSave={async () => {}} batches={batches} academyId={academy?.academyId || ''} students={students} academy={academy!} />;
            case 'edit-student': return selectedStudentId ? <EditStudentPage onBack={() => setPage('active-students')} student={students.find(s => s.id === selectedStudentId)!} batches={batches} onUpdate={async () => {}} /> : null;
            case 'student-details':
                const currentStudent = students.find(s => s.id === selectedStudentId);
                if (!currentStudent) return <Dashboard onNavigate={setPage} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                return <StudentDetailsPage onBack={() => setPage('active-students')} student={currentStudent} feeCollections={feeCollections.filter(f => f.studentId === currentStudent.id)} academyId={academyId} onSavePayment={async () => {}} transportRoutes={transportRoutes} onShowImage={setImageToView} academy={academy!} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} currentUserRole={currentUser?.role === 'admin' || currentUser?.role === 'staff' ? currentUser?.role : undefined} />;
            case 'birthday-list': return <BirthdayListPage onBack={() => setPage('student-options')} students={students} />;
            case 'registration-form-list': return <RegistrationFormListPage onBack={() => setPage('student-options')} students={students} onSelectStudent={(id) => { setSelectedStudentId(id); setPage('registration-form-view'); }} />;
            case 'registration-form-view': return selectedStudentId ? <RegistrationFormViewPage onBack={() => setPage('registration-form-list')} student={students.find(s => s.id === selectedStudentId)!} transportRoutes={transportRoutes} academy={academy!} /> : null;

            // Batch Management
            case 'batches': return <BatchesPage onBack={() => setPage('dashboard')} onCreate={() => setPage('new-batch')} batches={batches} onViewStudents={(filter) => { setStudentListFilter(filter); setPage('active-students'); }} onEditBatch={(id) => { setSelectedBatchId(id); setPage('edit-batch'); }} />;
            case 'new-batch': return <NewBatchPage onBack={() => setPage('batches')} onSave={async () => {}} />;
            case 'edit-batch': return selectedBatchId ? <EditBatchPage onBack={() => setPage('batches')} onSave={async () => {}} batch={batches.find(b => b.id === selectedBatchId)!} /> : null;

            // Attendance
            case 'select-batch-attendance': return <SelectBatchForAttendancePage onBack={() => setPage('dashboard')} batches={batches} onSelectBatch={(id) => { setSelectedBatchId(id); setPage('take-attendance'); }} academyId={academyId} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'take-attendance': return selectedBatchId ? <TakeAttendancePage onBack={() => setPage('select-batch-attendance')} batch={batches.find(b => b.id === selectedBatchId)!} students={students} academy={academy!} isDemoMode={isDemoMode} onShowImage={setImageToView} /> : null;

            // Fees
            case 'fees-options': return <FeesOptionsPage onBack={() => setPage('dashboard')} onNavigate={setPage} />;
            case 'fee-collection-report': return <FeeCollectionReportPage onBack={() => setPage('fees-options')} feeCollections={feeCollections} onDelete={async () => {}} onUpdate={async () => {}} isDemoMode={isDemoMode} />;
            case 'fee-dues-list': return <FeeDuesListPage onBack={() => setPage('fees-options')} students={students} batches={batches} feeCollections={feeCollections} academy={academy!} />;
            case 'select-batch-for-fees': return <SelectBatchForFeesPage onBack={() => setPage('fees-options')} batches={batches} onSelectBatch={(id) => { setSelectedBatchId(id); setPage('select-student-for-fees'); }} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'select-student-for-fees': return selectedBatchId ? <SelectStudentForFeesPage onBack={() => setPage('select-batch-for-fees')} batch={batches.find(b => b.id === selectedBatchId)!} students={students} onSelectStudent={(id) => { setSelectedStudentId(id); setPage('student-fee-details'); }} /> : null;
            case 'student-fee-details': return selectedStudentId ? <StudentFeeDetailsPage onBack={() => setPage('select-student-for-fees')} student={students.find(s => s.id === selectedStudentId)!} feeCollections={feeCollections.filter(f => f.studentId === selectedStudentId)} onSavePayment={async () => {}} academy={academy!} /> : null;

            // Timetable / Schedule
            case 'schedule-classes': return <ScheduleClassesPage onBack={() => setPage('dashboard')} batches={batches} staff={staff} academyId={academyId} onSave={handleSaveSchedule} isDemoMode={isDemoMode} />;

            // Finance
            case 'income-expenses': return <IncomeExpensesPage onBack={() => setPage('dashboard')} transactions={transactions} isDemoMode={isDemoMode} onSave={async () => {}} onUpdate={async () => {}} onDelete={async () => {}} />;

            // Exams
            case 'manage-exams': return <ManageExamsPage onBack={() => setPage('dashboard')} exams={exams} onNavigate={handleNavigate} onPublish={async () => {}} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'create-exam': return <CreateExamPage onBack={() => setPage('manage-exams')} onSave={async () => {}} batches={batches} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'record-marks': return pageParams.examId ? <RecordMarksPage onBack={() => setPage('manage-exams')} exam={exams.find(e => e.id === pageParams.examId)!} students={students} academy={academy!} isDemoMode={isDemoMode} onPublish={async () => {}} /> : null;

            // Staff Management
            case 'staff-options': return <StaffOptionsPage onBack={() => setPage('dashboard')} onNavigate={setPage} />;
            case 'staff-manager': return <StaffManagerPage onBack={() => setPage('staff-options')} staff={staff} onManageAccess={(id) => { setSelectedStaffId(id); setPage('staff-batch-access'); }} onToggleStatus={async () => {}} onShowDevPopup={handleShowDevPopup} />;
            case 'new-staff': return <NewStaffPage onBack={() => setPage('staff-options')} onSave={async () => {}} staff={staff} />;
            case 'inactive-staff': return <InactiveStaffPage onBack={() => setPage('staff-options')} staff={staff} onToggleStatus={async () => {}} />;
            case 'staff-batch-access': return selectedStaffId ? <StaffBatchAccessPage onBack={() => setPage('staff-manager')} staff={staff.find(s => s.id === selectedStaffId)!} batches={batches} onSave={async () => {}} /> : null;
            case 'mark-staff-attendance': return <MarkStaffAttendancePage onBack={() => setPage('staff-options')} batches={batches} staff={staff} academyId={academyId} isDemoMode={isDemoMode} staffAttendance={staffAttendance} onSave={async () => {}} onDelete={async () => {}} />;
            case 'staff-attendance-report': return <StaffAttendanceReportPage onBack={() => setPage('staff-options')} staff={staff} staffAttendance={staffAttendance} />;
            case 'manage-salaries': return <ManageSalariesPage onBack={() => setPage('staff-options')} staff={staff} salaryPayments={salaryPayments} onSave={async () => {}} onDelete={async () => {}} isDemoMode={isDemoMode} />;

            // Reports & LMS
            case 'reports-options': return <ReportsPage onBack={() => setPage('dashboard')} onNavigate={setPage} onShowDevPopup={handleShowDevPopup} />;
            case 'attendance-report': return <AttendanceReportPage onBack={() => setPage('reports-options')} batches={batches} students={students} academyId={academyId} academy={academy!} />;
            case 'study-material': return <StudyMaterialPage onBack={() => setPage('dashboard')} materials={studyMaterials} batches={batches} onNavigate={handleNavigate} onDelete={async () => {}} />;
            case 'upload-study-material': return <UploadStudyMaterialPage onBack={() => setPage('study-material')} onSave={async () => {}} batches={batches} academyId={academyId} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser?.data.name || ''} isDemoMode={isDemoMode} />;
            case 'homework': return <HomeworkPage onBack={() => setPage('dashboard')} homework={homework} batches={batches} onNavigate={handleNavigate} onDelete={async () => {}} />;
            case 'assign-homework': return <AssignHomeworkPage onBack={() => setPage('homework')} onSave={async () => {}} batches={batches} academyId={academyId} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser?.data.name || ''} isDemoMode={isDemoMode} />;
            case 'manage-quizzes': return <ManageQuizzesPage onBack={() => setPage('dashboard')} quizzes={quizzes} onNavigate={handleNavigate} onDelete={async () => {}} onShowDevPopup={handleShowDevPopup} />;
            case 'create-quiz': return <CreateQuizPage onBack={() => setPage('manage-quizzes')} onSave={async () => {}} batches={batches} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;

            // Utilities
            case 'leave-manager': return <LeaveManagerPage onBack={() => setPage('dashboard')} leaveRequests={leaveRequests} students={students} staff={staff} currentUser={currentUser!} batches={batches} onUpdateStatus={async () => {}} />;
            case 'todo-task': return <TodoTaskPage onBack={() => setPage('dashboard')} tasks={tasks} staff={staff} onSaveTask={async () => {}} onToggleTaskStatus={async () => {}} onDeleteTask={async () => {}} isDemoMode={isDemoMode} />;
            case 'notice-board': return <NoticeBoardPage onBack={() => setPage('dashboard')} notices={notices} onSaveNotice={async () => {}} onDeleteNotice={async () => {}} isDemoMode={isDemoMode} academyId={academyId} />;
            case 'transport-options': return <TransportOptionsPage onBack={() => setPage('dashboard')} onCreate={() => setPage('new-transport-route')} routes={transportRoutes} onNavigate={handleNavigate} onDelete={async () => {}} />;
            case 'settings': return <SettingsPage onBack={() => setPage('dashboard')} onNavigate={setPage} onShowDevPopup={handleShowDevPopup} />;
            case 'custom-sms-settings': return <CustomSmsSettingsPage onBack={() => setPage('settings')} academy={academy!} onSave={async () => {}} />;
            case 'notifications': return <NotificationsPage onBack={() => setPage('dashboard')} enquiries={enquiries.filter(e => e.status === 'New')} leaveRequests={leaveRequests.filter(l => l.status === 'Pending')} unmarkedAttendanceBatches={[]} scheduleAlerts={[]} onNavigate={setPage} />;
            case 'legal': return <LegalPage onBack={() => setPage('dashboard')} />;
            case 'my-account': return <MyAccountPage onBack={() => setPage('dashboard')} onSave={async () => {}} onLogout={handleLogout} academy={academy!} />;
            case 'subscription': return <SubscriptionPage onBack={() => setPage('dashboard')} academy={academy!} onSubscribe={handleSubscribe} />;

            // Student/Staff Dashboard Fallbacks
            default:
                if (currentUser?.role === 'admin') return <Dashboard onNavigate={setPage} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                if (currentUser?.role === 'student') return <StudentDashboardPage student={currentUser.data} academy={academy!} feeCollections={feeCollections} batches={batches} onNavigate={setPage} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                if (currentUser?.role === 'staff') return <StaffDashboardPage onNavigate={setPage} academy={academy!} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                return null;
        }
    };

    const MainLayout: React.FC<{ children: React.ReactNode }> = ({ children }) => (
        <div className={`min-h-screen font-sans ${theme} bg-gray-100 dark:bg-gray-900`}>
            {isPlaceholderConfig && page !== 'onboarding' && <ConfigurationWarning />}
            {connectionError && <ConnectionErrorBanner message={connectionError} onClose={() => setConnectionError(null)} />}
            {isOffline && <OfflineIndicator />}
            {currentUser?.role === 'admin' && academy && (
                 <>
                     {page === 'dashboard' && <Header academy={academy} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={setPage} notificationCount={0} />}
                     <SideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                     <main className="pb-20">{children}</main>
                     {page === 'dashboard' && <BottomNav onNavigate={setPage} activePage={page} onOpenChatbot={() => setIsChatbotOpen(true)} />}
                 </>
            )}
            {currentUser?.role === 'student' && academy && (
                <>
                    <StudentSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} systemLogoUrl={systemLogoUrl} />
                    <main>{children}</main>
                </>
            )}
            {currentUser?.role === 'staff' && academy && (
                <>
                    {page === 'dashboard' && <StaffHeader staffName={currentUser.data.name} academyName={academy.name} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={setPage} notificationCount={0} />}
                    <StaffSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                    <main>{children}</main>
                </>
            )}
            {showDevPopup && <DevInProgressPopup featureName={showDevPopup} onClose={() => setShowDevPopup(null)} />}
            {imageToView && <FullScreenImageViewer src={imageToView} alt="Full screen view" onClose={() => setImageToView(null)} />}
             {isChatbotOpen && academy && (
                <AIChatbot isOpen={isChatbotOpen} onClose={() => setIsChatbotOpen(false)} onNavigate={(p) => { handleNavigate(p); setIsChatbotOpen(false); }} students={students} feeCollections={feeCollections} batches={batches} academyId={academy.id} />
            )}
        </div>
    );

    if (isLoading) return <SplashScreen />;
    if (!currentUser) return (
        <div className="min-h-screen flex flex-col">
            {isPlaceholderConfig && <ConfigurationWarning />}
            {page === 'onboarding' && <OnboardingPage onComplete={() => { localStorage.setItem('onboardingCompleted', 'true'); setPage('role-selection'); }} />}
            {page === 'role-selection' && <RoleSelectionPage onSelectRole={(role) => { localStorage.setItem('lastSelectedRole', role); setLoginPageRole(role); setPage('login'); }} onBack={() => {}} />}
            {page === 'register' && <RegisterPage onNavigateToLogin={() => setPage('login')} />}
            {page === 'complete-registration' && <CompleteRegistrationPage onComplete={async () => {}} onLogout={handleLogout} userEmail={auth.currentUser?.email || ''} externalError={authError} clearExternalError={() => setAuthError(null)} />}
            {page !== 'onboarding' && page !== 'role-selection' && page !== 'register' && page !== 'complete-registration' &&
                <LoginPage onLogin={handleLogin} onNavigateToRegister={() => setPage('register')} externalError={authError} clearExternalError={() => setAuthError(null)} initialRole={loginPageRole} onGoBack={() => { localStorage.removeItem('lastSelectedRole'); setPage('role-selection'); }} systemLogoUrl={systemLogoUrl} />
            }
        </div>
    );

    return <MainLayout>{renderPage()}</MainLayout>;
}

