export function SubscriptionPage({ onBack, academy, onSubscribe, isModal = false }: SubscriptionPageProps) {
    const [isLoading, setIsLoading] = React.useState<string | null>(null);

    const handlePayment = async (plan: typeof plans[0]) => {
        const platformKey = PLATFORM_CONFIG.razorpayKeyId;

        if (!platformKey || platformKey.includes('YOUR_PLATFORM_KEY')) {
            alert("Payment configuration is missing. Please contact the platform administrator.");
            return;
        }

        setIsLoading(plan.id);

        const options = {
            key: platformKey,
            amount: plan.amount,
            currency: "INR",
            name: "OptiLearn Subscription",
            description: `Payment for ${plan.title} Plan`,
            image: "data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iNjQiIGhlaWdodD0iNjQiIHZpZXdCb3g9IjAgMCAyOCAyNiIgZmlsbD0ibm9uZSIgeG1sbnM9Imh0dHA6Ly93d3cudzMub3JnLzIwMDAvc3ZnIj48cGF0aCBkPSJNMTAgMTIgSDE4IFYxNSBIMjIgVjIxIEg2IFYxNSBIMTAgVjEyIFoiIGZpbGw9IiNENUwMDAwIi8+PHBhdGggZD0iTTggNSBIMjAgTDE4IDExIEgxMCBaIiBmaWxsPSIjRDUwMDAwIi8+PC9zdmc+",
            // Standard integration capture setting
            payment_capture: 1, 
            handler: async (response: any) => {
                try {
                    await onSubscribe(plan.id as any, plan.months, { paymentId: response.razorpay_payment_id, amount: plan.amount });
                } catch (error) {
                    console.error("Firestore update failed after payment:", error);
                    alert("Payment was successful, but we couldn't update your subscription. Please contact support with Payment ID: " + response.razorpay_payment_id);
                } finally {
                    setIsLoading(null);
                }
            },
            prefill: {
                name: academy.adminName || academy.name,
                email: academy.adminEmail,
                contact: academy.contactPhone || ""
            },
            notes: {
                academy_id: academy.id,
                academy_name: academy.name,
                plan_id: plan.id
            },
            theme: {
                color: "#4f46e5"
            },
            retry: {
                enabled: true,
                max_count: 3
            },
            modal: {
                ondismiss: () => {
                    setIsLoading(null);
                }
            }
        };

        try {
            const rzp = new window.Razorpay(options);
            rzp.on('payment.failed', function (response: any){
                console.error('Payment Failed:', response.error);
                alert("Payment failed: " + response.error.description);
                setIsLoading(null);
            });
            rzp.open();
        } catch (error) {
            console.error("Razorpay Error:", error);
            alert("Could not initialize payment gateway. Please check your internet connection.");
            setIsLoading(null);
        }
    };

    const StatusIndicator = () => {
        const { subscriptionStatus, trialEndsAt, subscriptionEndsAt } = academy;
        let text = "Your subscription is expired.";
        let color = "bg-red-100 text-red-800 dark:bg-red-900/40 dark:text-red-300";
        let dateInfo = "";

        if (subscriptionStatus === 'trialing' && trialEndsAt) {
            const daysLeft = Math.ceil((trialEndsAt.toMillis() - Date.now()) / (1000 * 60 * 60 * 24));
            text = daysLeft > 0 ? `Trial Active: ${daysLeft} day(s) remaining.` : "Trial Expired";
            color = daysLeft > 0 ? "bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300" : color;
            dateInfo = `Expires on: ${trialEndsAt.toDate().toLocaleDateString()}`;
        } else if (subscriptionStatus === 'active' && subscriptionEndsAt) {
            const endDate = subscriptionEndsAt.toDate();
            text = `Plan Active: ${academy.plan ? academy.plan.charAt(0).toUpperCase() + academy.plan.slice(1) : ''}`;
            color = "bg-green-100 text-green-800 dark:bg-green-900/40 dark:text-green-300";
            dateInfo = `Expires on: ${endDate.toLocaleDateString('en-US', { day: 'numeric', month: 'long', year: 'numeric' })}`;
        }

        return (
            <div className={`p-4 rounded-lg flex flex-col items-center justify-center ${color} mb-6 border`}>
                <span className="font-bold text-lg">{text}</span>
                {dateInfo && <span className="text-sm mt-1 opacity-90 font-medium">{dateInfo}</span>}
            </div>
        );
    };

    const plansContent = (
         <>
            <StatusIndicator />
            <div className="text-center my-8">
                <h2 className="text-3xl font-bold text-gray-900 dark:text-white">Choose Your Plan</h2>
                <p className="mt-2 text-gray-600 dark:text-gray-400">Select the perfect plan for your institute's needs.</p>
            </div>
            <div className="space-y-8 lg:space-y-0 lg:grid lg:grid-cols-3 lg:gap-8 mb-8">
                {plans.map(plan => (
                    <PlanCard 
                        key={plan.id}
                        title={plan.title}
                        price={plan.price}
                        period={plan.period}
                        features={plan.features}
                        isPopular={plan.isPopular}
                        onSelect={() => handlePayment(plan)}
                        isCurrent={academy.plan === plan.id && academy.subscriptionStatus === 'active'}
                        isLoading={isLoading === plan.id}
                        disabled={!!isLoading}
                    />
                ))}
            </div>
        </>
    );

    if (isModal) {
        return (
            <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center z-50 p-4 animate-fade-in">
                <div className="bg-gray-100 dark:bg-gray-900 rounded-2xl shadow-lg w-full max-w-4xl max-h-[90vh] flex flex-col">
                    <header className="flex-shrink-0 p-4 flex justify-between items-center border-b dark:border-gray-700 bg-white dark:bg-gray-800 rounded-t-2xl">
                         <h1 className="text-xl font-bold text-gray-800 dark:text-gray-100">Subscription & Billing</h1>
                         <button onClick={onBack} className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700">
                            <XMarkIcon className="w-6 h-6 text-gray-600 dark:text-gray-300"/>
                        </button>
                    </header>
                    <main className="flex-grow p-4 overflow-y-auto">
                        {plansContent}
                    </main>
                </div>
            </div>
        );
    }

    return (
        <div className="animate-fade-in flex flex-col h-full bg-gray-100 dark:bg-gray-900">
            <header className="bg-indigo-700 text-white p-3 flex items-center shadow-md flex-shrink-0 sticky top-0 z-10">
                <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-indigo-800 transition-colors" aria-label="Go back">
                    <ArrowLeftIcon className="w-6 h-6" />
                </button>
                <h1 className="text-xl font-bold ml-2">Subscription & Billing</h1>
            </header>
            <main className="flex-grow p-4 overflow-y-auto">
                {plansContent}
            </main>
        </div>
    );
}

import * as functions from 'firebase-functions';
import * as admin from 'firebase-admin';
import * as crypto from 'crypto';

admin.initializeApp();
const db = admin.firestore();

/**
 * Razorpay Webhook Handler
 * This endpoint should be added to the Razorpay Dashboard:
 * https://<region>-<project-id>.cloudfunctions.net/razorpayWebhook
 */
export const razorpayWebhook = functions.https.onRequest(async (req, res) => {
    // Only accept POST requests
    if (req.method !== 'POST') {
        res.status(405).send('Method Not Allowed');
        return;
    }

    const signature = req.headers['x-razorpay-signature'] as string;

    // We fetch the secret from a dedicated system config document in Firestore
    // The Platform Owner should set this in the Super Admin panel
    const systemConfig = await db.doc('system_config/payments').get();
    const webhookSecret = systemConfig.data()?.webhookSecret;

    if (!webhookSecret) {
        console.error('Webhook Secret not configured in Firestore (system_config/payments)');
        res.status(500).send('Internal Server Error: Missing Configuration');
        return;
    }

    // Verify the signature
    const shasum = crypto.createHmac('sha256', webhookSecret);
    shasum.update(JSON.stringify(req.body));
    const digest = shasum.digest('hex');

    if (digest !== signature) {
        console.warn('Invalid Razorpay signature detected.');
        res.status(400).send('Invalid signature');
        return;
    }

    const event = req.body.event;
    const payload = req.body.payload;

    console.log(`Processing Razorpay event: ${event}`);

    try {
        if (event === 'payment.captured' || event === 'order.paid') {
            const payment = payload.payment.entity;
            const notes = payment.notes;
            const academyId = notes.academy_id;
            const planId = notes.plan_id;

            if (!academyId || !planId) {
                console.error('Academy ID or Plan ID missing in payment notes');
                res.status(200).send('Processed but missing metadata'); // Return 200 so Razorpay stops retrying
                return;
            }

            // Calculate subscription extension based on plan
            let monthsToAdd = 1;
            if (planId === 'quarterly') monthsToAdd = 3;
            if (planId === 'yearly') monthsToAdd = 12;

            const academyRef = db.collection('academies').doc(academyId);
            const academyDoc = await academyRef.get();

            if (!academyDoc.exists) {
                console.error(`Academy ${academyId} not found`);
                res.status(200).send('Academy not found');
                return;
            }

            const academyData = academyDoc.data();
            const now = admin.firestore.Timestamp.now().toDate();

            // Determine starting point for extension
            let startDate = now;
            if (academyData?.subscriptionStatus === 'active' && academyData?.subscriptionEndsAt) {
                const currentEnd = academyData.subscriptionEndsAt.toDate();
                if (currentEnd > now) {
                    startDate = currentEnd;
                }
            }

            const newEndDate = new Date(startDate);
            newEndDate.setMonth(newEndDate.getMonth() + monthsToAdd);

            // Update Academy Record
            await academyRef.update({
                plan: planId,
                subscriptionStatus: 'active',
                subscriptionEndsAt: admin.firestore.Timestamp.fromDate(newEndDate),
                lastPaymentId: payment.id,
                updatedAt: admin.firestore.FieldValue.serverTimestamp()
            });

            // Log Transaction in Academy's sub-collection
            await academyRef.collection('transactions').add({
                type: 'Expense',
                category: 'Subscription',
                amount: payment.amount / 100,
                paymentMethod: payment.method === 'upi' ? 'UPI' : 'Card',
                description: `OptiLearn ${planId} plan (Webhook confirmed)`,
                date: admin.firestore.FieldValue.serverTimestamp(),
                createdAt: admin.firestore.FieldValue.serverTimestamp(),
                razorpay_payment_id: payment.id,
                razorpay_order_id: payment.order_id
            });

            console.log(`Successfully updated subscription for Academy: ${academyId}`);
        }

        res.status(200).send('Webhook Processed');
    } catch (error) {
        console.error('Error processing webhook:', error);
        res.status(500).send('Internal Server Error');
    }
});

