    );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { collection, getDocs, doc, updateDoc, deleteDoc, Timestamp, onSnapshot, setDoc } from 'firebase/firestore';
import { db } from '../firebaseConfig';
import type { Academy } from '../types';
import { LogoIcon } from './icons/LogoIcon';
import { LogoutIcon } from './icons/LogoutIcon';
import { PauseIcon } from './icons/PauseIcon';
import { PlayIcon } from './icons/PlayIcon';
import { TrashIcon } from './icons/TrashIcon';
import { LoadingSpinner } from './LoadingSpinner';
import { DashboardIcon } from './icons/DashboardIcon';
import { BuildingIcon } from './icons/BuildingIcon';
import { ChartPieIcon } from './icons/ChartPieIcon';
import { SettingsIcon } from './icons/SettingsIcon';
import { UsersGroupIcon } from './icons/UsersGroupIcon';
import { BriefcaseIcon } from './icons/BriefcaseIcon';
import { CreditCardIcon } from './icons/CreditCardIcon';
import { SearchIcon } from './icons/SearchIcon';
import { XMarkIcon } from './icons/XMarkIcon';
import { EyeIcon } from './icons/EyeIcon';
import { PencilIcon } from './icons/PencilIcon';
import { TerminalIcon } from './icons/TerminalIcon';
import { RefreshIcon } from './icons/RefreshIcon';
import { CameraIcon } from '../../components/icons/CameraIcon';
import { SystemLogo } from '../../components/SystemLogo';
import { KeyIcon } from '../../components/icons/KeyIcon';
import { ClipboardDocumentIcon } from '../../components/icons/ClipboardDocumentIcon';

type AcademyWithCounts = Academy & { studentCount: number; staffCount: number; countsLoaded?: boolean };
type Tab = 'dashboard' | 'academies' | 'analytics' | 'settings';

const StatCard: React.FC<{ title: string; value: string | number; details?: string; icon: React.ReactNode; color: string }> = ({ title, value, details, icon, color }) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center space-x-4">
        <div className={`w-12 h-12 rounded-full flex items-center justify-center ${color} text-white`}>
            {icon}
        </div>
        <div>
            <p className="text-sm text-gray-500 font-medium">{title}</p>
            <p className="text-2xl font-bold text-gray-800">{value}</p>
            {details && <p className="text-xs text-gray-400 mt-1">{details}</p>}
        </div>
    </div>
);

const SubscriptionModal: React.FC<{
    academy: AcademyWithCounts;
    onClose: () => void;
    onSave: (academyId: string, updates: Partial<Academy>) => Promise<void>;
}> = ({ academy, onClose, onSave }) => {
    const [plan, setPlan] = useState<'monthly' | 'quarterly' | 'yearly'>(academy.plan || 'monthly');
    const [status, setStatus] = useState<'active' | 'trialing' | 'expired' | 'cancelled'>(academy.subscriptionStatus || 'trialing');

    const initialDate = academy.subscriptionEndsAt?.toDate().toISOString().split('T')[0] 
        || academy.trialEndsAt?.toDate().toISOString().split('T')[0] 
        || new Date().toISOString().split('T')[0];

    const [expiryDate, setExpiryDate] = useState(initialDate);
    const [isSaving, setIsSaving] = useState(false);

    const handleSave = async () => {
        if (!expiryDate) return;
        setIsSaving(true);
        const endData = new Date(expiryDate);
        endData.setHours(23, 59, 59, 999);
        const updates: Partial<Academy> = { plan, subscriptionStatus: status };
        if (status === 'trialing') {
            updates.trialEndsAt = Timestamp.fromDate(endData);
            updates.subscriptionEndsAt = null as any;
        } else {
            updates.subscriptionEndsAt = Timestamp.fromDate(endData);
        }
        await onSave(academy.id, updates);
        setIsSaving(false);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 animate-fade-in p-4">
            <div className="bg-white p-6 rounded-2xl shadow-xl w-full max-w-md text-gray-800">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-bold">Manage Subscription</h3>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-100 text-gray-500"><XMarkIcon className="w-6 h-6" /></button>
                </div>
                <div className="mb-6 p-4 bg-gray-50 rounded-lg border border-gray-100">
                    <p className="text-sm text-gray-500 mb-1">Academy</p>
                    <p className="font-bold text-lg">{academy.name}</p>
                    <p className="text-xs text-gray-400">ID: {academy.academyId}</p>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Plan Type</label>
                        <select value={plan} onChange={(e) => setPlan(e.target.value as any)} className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none">
                            <option value="monthly">Monthly</option>
                            <option value="quarterly">Quarterly</option>
                            <option value="yearly">Yearly</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                        <select value={status} onChange={(e) => setStatus(e.target.value as any)} className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none">
                            <option value="active">Active</option>
                            <option value="trialing">Trialing</option>
                            <option value="expired">Expired</option>
                            <option value="cancelled">Cancelled</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Expiry Date</label>
                        <input type="date" value={expiryDate} onChange={(e) => setExpiryDate(e.target.value)} className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" />
                    </div>
                </div>
                <div className="mt-8 flex justify-end gap-3">
                    <button onClick={onClose} className="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg font-semibold hover:bg-gray-300 transition-colors">Cancel</button>
                    <button onClick={handleSave} disabled={isSaving} className="px-4 py-2 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition-colors disabled:bg-indigo-400">
                        {isSaving ? 'Saving...' : 'Save Changes'}
                    </button>
                </div>
            </div>
        </div>
    );
};

// Added SuperAdminPanelProps interface to fix line 123 error
interface SuperAdminPanelProps {
    onLogout: () => void;
}

export function SuperAdminPanel({ onLogout }: SuperAdminPanelProps): React.ReactNode {
    const [activeTab, setActiveTab] = useState<Tab>('dashboard');
    const [academies, setAcademies] = useState<AcademyWithCounts[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [actionError, setActionError] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [subFilter, setSubFilter] = useState('all');
    const [managingSub, setManagingSub] = useState<AcademyWithCounts | null>(null);
    const [systemLogoUrl, setSystemLogoUrl] = useState<string | null>(null);
    const [isSavingLogo, setIsSavingLogo] = useState(false);

    // Webhook settings
    const [webhookSecret, setWebhookSecret] = useState('');
    const [isSavingWebhook, setIsSavingWebhook] = useState(false);
    const [copiedUrl, setCopiedUrl] = useState(false);

    useEffect(() => {
        setIsLoading(true);
        const unsubscribe = onSnapshot(collection(db, 'academies'), (snapshot) => {
            const academyList = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data(),
                status: doc.data().status || 'active',
                studentCount: 0,
                staffCount: 0,
                countsLoaded: false
            } as AcademyWithCounts));

            setAcademies(prev => {
                const prevMap = new Map<string, AcademyWithCounts>(prev.map(a => [a.id, a]));
                return academyList.map(newAcademy => {
                    const existing = prevMap.get(newAcademy.id);
                    if (existing && existing.countsLoaded) {
                        return { ...newAcademy, studentCount: existing.studentCount, staffCount: existing.staffCount, countsLoaded: true };
                    }
                    return newAcademy;
                });
            });
            setIsLoading(false);
        });

        const unsubConfig = onSnapshot(doc(db, 'system_config', 'main'), (docSnap) => {
            if (docSnap.exists()) setSystemLogoUrl(docSnap.data().logoUrl || null);
        });

        const unsubPayments = onSnapshot(doc(db, 'system_config', 'payments'), (docSnap) => {
            if (docSnap.exists()) setWebhookSecret(docSnap.data().webhookSecret || '');
        });

        return () => { unsubscribe(); unsubConfig(); unsubPayments(); };
    }, []);

    useEffect(() => {
        const loadCounts = async () => {
            const academiesToUpdate = academies.filter(a => !a.countsLoaded);
            if (academiesToUpdate.length === 0) return;
            for (const academy of academiesToUpdate) {
                try {
                    const studentsSnapshot = await getDocs(collection(db, 'academies', academy.id, 'students'));
                    const staffSnapshot = await getDocs(collection(db, 'academies', academy.id, 'staff'));
                    setAcademies(prev => prev.map(a => a.id === academy.id ? { ...a, studentCount: studentsSnapshot.size, staffCount: staffSnapshot.size, countsLoaded: true } : a));
                } catch (e) { console.error(e); }
            }
        };
        const timer = setTimeout(loadCounts, 500);
        return () => clearTimeout(timer);
    }, [academies.length]);

    const handleSaveWebhookSecret = async () => {
        setIsSavingWebhook(true);
        try {
            await setDoc(doc(db, 'system_config', 'payments'), { webhookSecret }, { merge: true });
            alert("Webhook secret saved successfully!");
        } catch(err) {
            setActionError("Failed to save webhook secret.");
        } finally {
            setIsSavingWebhook(false);
        }
    };

    const webhookUrl = `https://us-central1-${db.app.options.projectId}.cloudfunctions.net/razorpayWebhook`;

    const handleCopyUrl = () => {
        navigator.clipboard.writeText(webhookUrl);
        setCopiedUrl(true);
        setTimeout(() => setCopiedUrl(false), 2000);
    };

    const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onloadend = async () => {
                const base64String = reader.result as string;
                setSystemLogoUrl(base64String);
                setIsSavingLogo(true);
                try {
                    await setDoc(doc(db, 'system_config', 'main'), { logoUrl: base64String }, { merge: true });
                } catch(err) { setActionError("Failed to save system logo."); }
                finally { setIsSavingLogo(false); }
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSaveSubscription = async (academyId: string, updates: Partial<Academy>) => {
        try { await updateDoc(doc(db, 'academies', academyId), updates); setManagingSub(null); }
        catch(err) { setActionError("Failed to update subscription."); }
    };

    const { totalStudents, totalStaff, subCounts } = useMemo(() => {
        const subs = { trialing: 0, active: 0, expired: 0 };
        let students = 0; let staff = 0;
        academies.forEach(a => {
            students += a.studentCount; staff += a.staffCount;
            if (a.subscriptionStatus && a.subscriptionStatus !== 'cancelled') (subs as any)[a.subscriptionStatus]++;
        });
        return { totalStudents: students, totalStaff: staff, subCounts: subs };
    }, [academies]);

    const filteredAcademies = useMemo(() => {
        return academies
            .filter(a => statusFilter === 'all' || a.status === statusFilter)
            .filter(a => subFilter === 'all' || a.subscriptionStatus === subFilter)
            .filter(a => a.name.toLowerCase().includes(searchTerm.toLowerCase()) || a.academyId.toLowerCase().includes(searchTerm.toLowerCase()) || a.adminEmail.toLowerCase().includes(searchTerm.toLowerCase()));
    }, [academies, statusFilter, subFilter, searchTerm]);

    const toggleAcademyStatus = async (academy: Academy) => {
        const newStatus = academy.status === 'active' ? 'paused' : 'active';
        try { await updateDoc(doc(db, 'academies', academy.id), { status: newStatus }); }
        catch (err) { setActionError(`Failed to update status for ${academy.name}.`); }
    };

    const deleteAcademy = async (academyId: string, academyName: string) => {
        if (!window.confirm(`DELETE ${academyName}? IRREVERSIBLE.`)) return;
        try { await deleteDoc(doc(db, 'academies', academyId)); }
        catch (err) { setActionError(`Failed to delete academy ${academyName}.`); }
    };

    // Added missing getSubscriptionStatusPill helper function to fix line 340 error
    const getSubscriptionStatusPill = (academy: Academy) => {
        const { subscriptionStatus, trialEndsAt } = academy;
        let text = 'N/A';
        let color = 'bg-gray-600';
        let subtext = '';

        if (subscriptionStatus === 'trialing') {
            const daysLeft = trialEndsAt ? Math.ceil((trialEndsAt.toMillis() - Date.now()) / (1000 * 60 * 60 * 24)) : 0;
            text = 'Trial';
            color = daysLeft > 3 ? 'bg-blue-500' : 'bg-yellow-500';
            subtext = daysLeft > 0 ? `${daysLeft} days left` : 'Expired';
        } else if (subscriptionStatus === 'active') {
            text = 'Active';
            color = 'bg-green-500';
        } else if (subscriptionStatus === 'expired') {
            text = 'Expired';
            color = 'bg-red-500';
        }
        return (
            <div className="flex flex-col items-center">
                 <span className={`px-2 py-1 text-xs font-semibold rounded-full text-white ${color}`}>
                    {text}
                </span>
                {subtext && <span className="text-xs text-gray-400 mt-1">{subtext}</span>}
            </div>
        );
    };

    return (
        <div className="bg-slate-50 text-gray-900 min-h-screen font-sans flex">
            <aside className="w-64 bg-white border-r border-gray-200 p-4 flex flex-col shadow-sm z-10">
                <div className="flex items-center space-x-3 mb-8 px-2">
                    <SystemLogo url={systemLogoUrl} className="w-10 h-10" />
                    <div><h1 className="text-lg font-bold text-gray-900">Super Admin</h1><p className="text-xs text-gray-500">OptiLearn</p></div>
                </div>
                <nav className="flex-grow space-y-1">
                    {[
                        { id: 'dashboard', label: 'Dashboard', icon: <DashboardIcon className="w-5 h-5"/> },
                        { id: 'academies', label: 'Academies', icon: <BuildingIcon className="w-5 h-5"/> },
                        { id: 'analytics', label: 'Analytics', icon: <ChartPieIcon className="w-5 h-5"/> },
                        { id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-5 h-5"/> },
                    ].map(item => (
                        <button key={item.id} onClick={() => setActiveTab(item.id as Tab)} className={`w-full flex items-center space-x-3 px-3 py-2.5 rounded-lg text-left transition-colors font-medium ${activeTab === item.id ? 'bg-indigo-50 text-indigo-700' : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'}`}>
                            {item.icon}<span>{item.label}</span>
                        </button>
                    ))}
                </nav>
                <div className="border-t border-gray-100 pt-4 mt-2">
                    <button onClick={onLogout} className="flex items-center space-x-2 px-3 py-2.5 bg-red-50 hover:bg-red-100 text-red-700 rounded-lg transition-colors w-full font-medium"><LogoutIcon className="w-5 h-5" /><span>Logout</span></button>
                </div>
            </aside>

            <div className="flex-1 flex flex-col h-screen overflow-hidden">
                <header className="bg-white border-b border-gray-200 p-4 flex justify-between items-center shadow-sm">
                    <h2 className="text-xl font-bold text-gray-800 capitalize">{activeTab}</h2>
                    <div className="flex items-center gap-2"><span className="flex h-3 w-3 relative"><span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span><span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span></span><span className="text-xs font-semibold text-gray-500">Live Updates Active</span></div>
                </header>

                <main className="flex-grow p-4 md:p-8 overflow-y-auto bg-slate-50">
                    {actionError && <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg relative mb-6 shadow-sm"><span className="block sm:inline">{actionError}</span><button onClick={() => setActionError(null)} className="absolute top-0 bottom-0 right-0 px-4 py-3"><span className="text-2xl">&times;</span></button></div>}
                    {isLoading && <LoadingSpinner message="Syncing platform data..." />}

                    {!isLoading && !error && (
                        <>
                           {activeTab === 'dashboard' && (
                               <div className="animate-fade-in-up">
                                   <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                                       <StatCard title="Total Academies" value={academies.length} details={`${academies.filter(a => a.status === 'active').length} Active`} icon={<BuildingIcon className="w-6 h-6"/>} color="bg-blue-600" />
                                       <StatCard title="Total Students" value={totalStudents.toLocaleString()} icon={<UsersGroupIcon className="w-6 h-6"/>} color="bg-green-600" />
                                       <StatCard title="Total Staff" value={totalStaff.toLocaleString()} icon={<BriefcaseIcon className="w-6 h-6"/>} color="bg-yellow-500" />
                                       <StatCard title="Active Subs" value={subCounts.active} details={`${subCounts.trialing} Trialing`} icon={<CreditCardIcon className="w-6 h-6"/>} color="bg-purple-600" />
                                   </div>
                               </div>
                           )}
                           {(activeTab === 'academies' || activeTab === 'dashboard') && (
                                <div className="animate-fade-in-up">
                                    <div className="bg-white rounded-xl overflow-hidden shadow-sm border border-gray-200">
                                        <div className="overflow-x-auto">
                                            <table className="w-full text-sm text-left">
                                                <thead className="bg-gray-50 text-gray-500 font-semibold border-b border-gray-200">
                                                    <tr>
                                                        <th className="p-4">Academy Details</th>
                                                        <th className="p-4">Stats</th>
                                                        <th className="p-4">Plan</th>
                                                        <th className="p-4">Subscription</th>
                                                        <th className="p-4">Status</th>
                                                        <th className="p-4 text-right">Actions</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-gray-100">
                                                    {filteredAcademies.map(academy => (
                                                        <tr key={academy.id} className="hover:bg-gray-50 transition-colors">
                                                            <td className="p-4">
                                                                <p className="font-bold text-gray-900 text-base">{academy.name}</p>
                                                                <p className="text-xs text-gray-500 font-mono mt-0.5">{academy.academyId}</p>
                                                                <p className="text-xs text-gray-400">{academy.adminEmail}</p>
                                                            </td>
                                                            <td className="p-4">
                                                                <div className="flex flex-col gap-1">
                                                                    <span className="inline-flex items-center gap-1.5 text-gray-600"><UsersGroupIcon className="w-4 h-4 text-gray-400"/> {academy.studentCount}</span>
                                                                    <span className="inline-flex items-center gap-1.5 text-gray-600"><BriefcaseIcon className="w-4 h-4 text-gray-400"/> {academy.staffCount}</span>
                                                                </div>
                                                            </td>
                                                            <td className="p-4"><span className="capitalize font-medium text-gray-700 bg-gray-100 px-2 py-1 rounded text-xs border border-gray-200">{academy.plan || 'Free'}</span></td>
                                                            <td className="p-4">{getSubscriptionStatusPill(academy)}</td>
                                                            <td className="p-4"><span className={`px-2.5 py-1 text-xs font-bold rounded-full border ${academy.status === 'active' ? 'bg-green-50 text-green-700 border-green-200' : 'bg-yellow-50 text-yellow-700 border-yellow-200'}`}>{academy.status?.toUpperCase()}</span></td>
                                                            <td className="p-4 text-right">
                                                                <div className="flex justify-end items-center gap-2">
                                                                    <button title="Manage Subscription" onClick={() => setManagingSub(academy)} className="p-2 rounded-lg bg-indigo-50 text-indigo-600 hover:bg-indigo-100 transition-colors"><PencilIcon className="w-4 h-4"/></button>
                                                                    <button title={academy.status === 'active' ? 'Pause Academy' : 'Activate Academy'} onClick={() => toggleAcademyStatus(academy)} className={`p-2 rounded-lg transition-colors ${academy.status === 'active' ? 'bg-yellow-50 text-yellow-600 hover:bg-yellow-100' : 'bg-green-50 text-green-600 hover:bg-green-100'}`}>{academy.status === 'active' ? <PauseIcon className="w-4 h-4"/> : <PlayIcon className="w-4 h-4"/>}</button>
                                                                    <button title="Delete Academy" onClick={() => deleteAcademy(academy.id, academy.name)} className="p-2 rounded-lg bg-red-50 text-red-600 hover:bg-red-100 transition-colors"><TrashIcon className="w-4 h-4"/></button>
                                                                </div>
                                                            </td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>
                           )}
                           {activeTab === 'settings' && (
                                <div className="animate-fade-in-up space-y-6">
                                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                                        <div className="flex items-center gap-4 mb-6">
                                            <div className="w-12 h-12 rounded-full bg-indigo-50 flex items-center justify-center"><KeyIcon className="w-6 h-6 text-indigo-600" /></div>
                                            <div><h3 className="text-lg font-bold text-gray-800">Razorpay Webhooks</h3><p className="text-sm text-gray-500">Enable automatic payment capture and subscription activation</p></div>
                                        </div>
                                        <div className="space-y-6">
                                            <div>
                                                <label className="block text-sm font-medium text-gray-700 mb-2">Webhook URL</label>
                                                <div className="flex gap-2">
                                                    <input type="text" readOnly value={webhookUrl} className="flex-1 bg-gray-50 border border-gray-300 rounded-lg p-3 text-sm text-gray-600 font-mono" />
                                                    <button onClick={handleCopyUrl} className="px-4 py-2 bg-gray-100 text-indigo-600 rounded-lg font-bold text-sm flex items-center gap-2 hover:bg-gray-200">
                                                        <ClipboardDocumentIcon className="w-4 h-4" /> {copiedUrl ? 'Copied' : 'Copy'}
                                                    </button>
                                                </div>
                                                <p className="text-xs text-gray-400 mt-2">Paste this URL in Razorpay Dashboard > Settings > Webhooks</p>
                                            </div>
                                            <div>
                                                <label className="block text-sm font-medium text-gray-700 mb-2">Webhook Secret</label>
                                                <div className="flex gap-2">
                                                    <input type="text" value={webhookSecret} onChange={(e) => setWebhookSecret(e.target.value)} placeholder="Enter Secret set in Razorpay" className="flex-1 bg-white border border-gray-300 rounded-lg p-3 text-sm outline-none focus:ring-2 focus:ring-indigo-500" />
                                                    <button onClick={handleSaveWebhookSecret} disabled={isSavingWebhook} className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-bold text-sm hover:bg-indigo-700 disabled:bg-indigo-400">
                                                        {isSavingWebhook ? 'Saving...' : 'Save Secret'}
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                                        <div className="flex items-center gap-4 mb-6">
                                            <div className="w-12 h-12 rounded-full bg-indigo-50 flex items-center justify-center"><EyeIcon className="w-6 h-6 text-indigo-600" /></div>
                                            <div><h3 className="text-lg font-bold text-gray-800">System Branding</h3><p className="text-sm text-gray-500">Update global app logo</p></div>
                                        </div>
                                        <div className="flex items-center gap-8">
                                            <div className="flex flex-col items-center">
                                                <div className="w-24 h-24 rounded-lg bg-gray-100 border border-gray-200 flex items-center justify-center overflow-hidden mb-2"><SystemLogo url={systemLogoUrl} className="w-16 h-16" /></div>
                                                <p className="text-xs text-gray-500">Current Logo</p>
                                            </div>
                                            <div className="flex-1">
                                                <label className="block text-sm font-medium text-gray-700 mb-2">Upload New Logo</label>
                                                <label className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg cursor-pointer hover:bg-gray-50 transition-colors w-fit">
                                                    <CameraIcon className="w-5 h-5 text-gray-500" /><span className="text-sm text-gray-700">Choose File</span>
                                                    <input type="file" accept="image/*" className="hidden" onChange={handleLogoUpload} />
                                                </label>
                                                {isSavingLogo && <p className="text-xs text-indigo-600 mt-2 font-medium">Saving logo...</p>}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                           )}
                        </>
                    )}
                </main>
            </div>
             {managingSub && <SubscriptionModal academy={managingSub} onClose={() => setManagingSub(null)} onSave={handleSaveSubscription} />}
        </div>
    );
}

