import { StaffNotificationsPage } from './components/staff/StaffNotificationsPage';
import { MarkStaffAttendancePage } from './components/MarkStaffAttendancePage';
import { StaffAttendanceReportPage } from './components/StaffAttendanceReportPage';
import { StaffAttendancePage } from './components/staff/StaffAttendancePage';
import { ManageSalariesPage } from './components/ManageSalariesPage';
import { StaffSalaryPage } from './components/staff/StaffSalaryPage';

import { TransportOptionsPage } from './components/TransportOptionsPage';
import { NewTransportRoutePage } from './components/NewTransportRoutePage';
import { EditTransportRoutePage } from './components/EditTransportRoutePage';
import { MapStudentsToRoutePage } from './components/MapStudentsToRoutePage';
import { AIChatbot } from './components/AIChatbot';
import { OnboardingPage } from './components/OnboardingPage';

const isPlaceholderConfig = firebaseConfig.apiKey.includes('placeholder');

const DevInProgressPopup: React.FC<{ featureName: string; onClose: () => void }> = ({ featureName, onClose }) => (
    <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center z-50 animate-fade-in p-4">
        <div className="bg-white dark:bg-gray-800 p-6 sm:p-8 rounded-2xl shadow-lg max-w-sm mx-auto text-center">
            <div className="mx-auto flex items-center justify-center h-16 w-16 rounded-full bg-yellow-100 dark:bg-yellow-900/40 mb-5">
                <WrenchIcon className="h-9 w-9 text-yellow-600 dark:text-yellow-400" />
            </div>
            <h2 className="text-xl sm:text-2xl font-bold text-gray-800 dark:text-gray-100 mb-3">Feature Under Development</h2>
            <p className="text-sm sm:text-base text-gray-600 dark:text-gray-400 mb-6">
                The "{featureName}" feature is not yet implemented. Please check back later!
            </p>
            <button
                onClick={onClose}
                className="w-full bg-indigo-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-indigo-700 transition-colors shadow-md"
            >
                Got it
            </button>
        </div>
    </div>
);

export default function App() {
    const [theme, setTheme] = useState<'light' | 'dark'>(() => {
        if (localStorage.getItem('theme') === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
          return 'dark';
        }
        return 'light';
    });

    type Role = 'academy' | 'student' | 'staff';

    const [page, setPage] = useState(() => {
        if (localStorage.getItem('onboardingCompleted')) {
            return 'role-selection';
        }
        return 'onboarding';
    });
    const [loginPageRole, setLoginPageRole] = useState<Role>('academy');
    const [pageParams, setPageParams] = useState<{[key: string]: any}>({});
    const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isNavOpen, setIsNavOpen] = useState(false);
    const [authError, setAuthError] = useState<string | null>(null);
    const [systemLogoUrl, setSystemLogoUrl] = useState<string | null>(null);

    // Navigation Stack for Mobile Back Button Handling
    const [history, setHistory] = useState<string[]>(['role-selection']);

    // Data state
    const [academy, setAcademy] = useState<Academy | null>(null);
    const [batches, setBatches] = useState<Batch[]>([]);
    const [students, setStudents] = useState<Student[]>([]);
    const [staff, setStaff] = useState<Staff[]>([]);
    const [staffAttendance, setStaffAttendance] = useState<StaffAttendance[]>([]);
    const [feeCollections, setFeeCollections] = useState<FeeCollection[]>([]);
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [exams, setExams] = useState<Exam[]>([]);
    const [enquiries, setEnquiries] = useState<Enquiry[]>([]);
    const [studyMaterials, setStudyMaterials] = useState<StudyMaterial[]>([]);
    const [homework, setHomework] = useState<Homework[]>([]);
    const [quizzes, setQuizzes] = useState<Quiz[]>([]);
    const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
    const [tasks, setTasks] = useState<Task[]>([]);
    const [notices, setNotices] = useState<Notice[]>([]);
    const [transportRoutes, setTransportRoutes] = useState<TransportRoute[]>([]);
    const [salaryPayments, setSalaryPayments] = useState<SalaryPayment[]>([]); 

    // Page-specific state
    const [selectedBatchId, setSelectedBatchId] = useState<string | null>(null);
    const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
    const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
    const [selectedExamId, setSelectedExamId] = useState<string | null>(null);
    const [selectedEnquiryId, setSelectedEnquiryId] = useState<string | null>(null);
    const [studentListFilter, setStudentListFilter] = useState('all');

    // UI State
    const [connectionError, setConnectionError] = useState<string | null>(null);
    const [isOffline, setIsOffline] = useState(!navigator.onLine);
    const [showDevPopup, setShowDevPopup] = useState<string | null>(null);
    const [imageToView, setImageToView] = useState<string | null>(null);
    const [isChatbotOpen, setIsChatbotOpen] = useState(false);

    // Initialize Native Features
    useEffect(() => {
        const initializeApp = async () => {
            if (Capacitor.isNativePlatform()) {
                await StatusBar.setStyle({ style: Style.Light });
                await CapSplashScreen.hide();

                // Native Back Button Handling
                CapApp.addListener('backButton', ({ canGoBack }) => {
                    if (page === 'dashboard' || page === 'login' || page === 'role-selection') {
                        // Exit the app if on a primary screen
                        CapApp.exitApp();
                    } else {
                        // Otherwise, go back one page
                        handleGoBack();
                    }
                });
            }
        };
        initializeApp();
    }, [page]);

    useEffect(() => {
        if (isPlaceholderConfig) return;
        const unsubConfig = onSnapshot(doc(db, 'system_config', 'main'), (docSnap) => {
            if (docSnap.exists()) {
                setSystemLogoUrl(docSnap.data().logoUrl || null);
            }
        });
        return () => unsubConfig();
    }, []);

    const isDemoMode = (currentUser?.role === 'admin' && currentUser.data.id === 'demo-academy-id') ||
        ((currentUser?.role === 'student' || currentUser?.role === 'staff') && currentUser.academyId === 'DEMO');

    useEffect(() => {
        if (theme === 'dark') {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [theme]);

    const handleToggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

    const handleNavigate = (newPage: string, params?: {[key: string]: any}) => {
        if (Capacitor.isNativePlatform()) Haptics.impact({ style: ImpactStyle.Light });
        setPageParams(params || {});
        setHistory(prev => [...prev, newPage]);
        setPage(newPage);
    };

    const handleGoBack = useCallback(() => {
        if (Capacitor.isNativePlatform()) Haptics.impact({ style: ImpactStyle.Light });
        if (history.length > 1) {
            const newHistory = [...history];
            newHistory.pop();
            const previousPage = newHistory[newHistory.length - 1];
            setHistory(newHistory);
            setPage(previousPage);
        } else {
            setPage('dashboard');
        }
    }, [history]);

    useEffect(() => {
        const handleOnline = () => setIsOffline(false);
        const handleOffline = () => setIsOffline(true);
        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);
        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    useEffect(() => {
        if (isPlaceholderConfig) {
            setIsLoading(false);
            if (!localStorage.getItem('onboardingCompleted')) setPage('onboarding');
            else if (localStorage.getItem('lastSelectedRole')) {
                 setLoginPageRole(localStorage.getItem('lastSelectedRole') as Role);
                 setPage('login');
            } else setPage('role-selection');
            return;
        }

        const unsubscribe = auth.onAuthStateChanged(async (user: firebase.User | null) => {
             try {
                if (user) {
                    if (user.isAnonymous) return;
                    const userDocRef = doc(db, "users", user.uid);
                    const userDocSnap = await getDoc(userDocRef);
                    if (userDocSnap.exists()) {
                        const userData = userDocSnap.data();
                        if (userData.role === 'admin' && userData.academyId) {
                            const academyDocRef = doc(db, "academies", userData.academyId);
                            const academyDocSnap = await getDoc(academyDocRef);
                            if (academyDocSnap.exists()) {
                                const academyData = { id: academyDocSnap.id, ...academyDocSnap.data() } as Academy;
                                setAcademy(academyData);
                                setCurrentUser({ role: 'admin', data: academyData });
                                setPage('dashboard');
                                setHistory(['dashboard']);
                            } else {
                                setAuthError("Your academy data is missing.");
                                setPage('complete-registration');
                            }
                        } else {
                            setAuthError("Account error.");
                            await auth.signOut();
                        }
                    } else {
                         setPage('complete-registration');
                    }
                } else {
                    setCurrentUser(null);
                    setAcademy(null);
                    if (localStorage.getItem('onboardingCompleted')) {
                         setPage(localStorage.getItem('lastSelectedRole') ? 'login' : 'role-selection');
                         setHistory(['role-selection']);
                    } else {
                        setPage('onboarding');
                    }
                }
            } catch (error) {
                console.error("Auth error", error);
            } finally {
                setIsLoading(false);
            }
        });
        return () => unsubscribe();
    }, []);

    useEffect(() => {
        if (!currentUser || isPlaceholderConfig || isDemoMode) {
            if (isDemoMode) {
                setAcademy({ id: 'demo', academyId: 'DEMO', name: 'Demo Academy', adminUid: 'demo', adminEmail: 'demo@test.com', status: 'active', subscriptionStatus: 'active' });
                setBatches(demoBatches);
                setStudents(demoStudents);
                setStaff(demoStaff);
                setTransactions(demoTransactions);
                setEnquiries(demoEnquiries);
                setTransportRoutes(demoTransportRoutes);
                setStaffAttendance(demoStaffAttendance);
            }
            return;
        };

        const academyId = (currentUser.role === 'admin') ? currentUser.data.id : currentUser.academyId;
        if (!academyId) return;

        const unsubscribers: (() => void)[] = [];

        const academyDocRef = doc(db, 'academies', academyId);
        unsubscribers.push(onSnapshot(academyDocRef, (docSnap) => {
            if (docSnap.exists()) {
                setAcademy({ id: docSnap.id, ...docSnap.data() } as Academy);
            }
        }));

        const collections = ['batches', 'students', 'staff', 'fees', 'transactions', 'exams', 'enquiries', 'studyMaterial', 'homework', 'quizzes', 'leaveRequests', 'tasks', 'notices', 'transportRoutes', 'staffAttendance', 'salaryPayments'];

        const setters: any = {
            batches: setBatches, students: setStudents, staff: setStaff, fees: setFeeCollections,
            transactions: setTransactions, exams: setExams, enquiries: setEnquiries, studyMaterial: setStudyMaterials,
            homework: setHomework, quizzes: setQuizzes, leaveRequests: setLeaveRequests, tasks: setTasks,
            notices: setNotices, transportRoutes: setTransportRoutes, staffAttendance: setStaffAttendance, salaryPayments: setSalaryPayments
        };

        collections.forEach(coll => {
             const collRef = collection(db, `academies/${academyId}/${coll}`);
             unsubscribers.push(onSnapshot(collRef, (snap) => {
                 setters[coll](snap.docs.map(d => ({ id: d.id, ...d.data() })));
             }));
        });

        return () => unsubscribers.forEach(u => u());
    }, [currentUser, isDemoMode]);

    const handleLogin = (user: CurrentUser) => {
        setAuthError(null);
        setCurrentUser(user);
        if (user.role === 'admin') setAcademy(user.data);
        setPage('dashboard');
        setHistory(['dashboard']);
    };

    const handleLogout = async () => {
        setIsNavOpen(false);
        if(!isDemoMode) await auth.signOut();
        setCurrentUser(null);
        setAcademy(null);
        localStorage.removeItem('lastSelectedRole');
        setPage('role-selection');
        setHistory(['role-selection']);
    };

    const handleShowDevPopup = (name: string) => setShowDevPopup(name);

    const handleToggleStudentStatus = async (studentId: string) => {
        if (isDemoMode) {
             setStudents(prev => prev.map(s => s.id === studentId ? { ...s, isActive: !s.isActive } : s));
             return;
        }
        if (!academy) return;
        const student = students.find(s => s.id === studentId);
        if (!student) return;
        try {
            await updateDoc(doc(db, `academies/${academy.id}/students`, studentId), {
                isActive: !student.isActive
            });
        } catch (error) {
            console.error("Error toggling student status:", error);
        }
    };

    const handleBulkSaveStudents = async (studentsData: Omit<Student, 'id' | 'isActive'>[]) => {
        if (!academy || isDemoMode) throw new Error("Cannot save in demo mode.");
        const chunkSize = 400;
        for (let i = 0; i < studentsData.length; i += chunkSize) {
            const chunk = studentsData.slice(i, i + chunkSize);
            const batch = writeBatch(db);
            chunk.forEach(studentData => {
                const studentRef = doc(collection(db, `academies/${academy.id}/students`));
                batch.set(studentRef, { ...studentData, isActive: true });
                studentData.batches.forEach(bName => {
                    const batchObj = batches.find(b => b.name.trim().toLowerCase() === bName.trim().toLowerCase());
                    if (batchObj) batch.update(doc(db, `academies/${academy.id}/batches`, batchObj.id), { currentStudents: increment(1) });
                });
            });
            await batch.commit();
        }
    };

    const handleSaveSchedule = async (date: string, batchId: string, scheduleItems: ScheduleItem[]) => {
        if (!academy || isDemoMode) return;
        try {
            const scheduleRef = doc(db, `academies/${academy.id}/schedules`, date);
            await setDoc(scheduleRef, { [batchId]: scheduleItems }, { merge: true });
        } catch (error) {
            console.error("Error saving schedule:", error);
            throw new Error("Failed to save schedule. Please check your internet connection.");
        }
    };

    const renderPage = () => {
        const student = currentUser?.role === 'student' ? currentUser.data : null;
        const academyId = academy?.id || '';

        switch (page) {
            case 'dashboard':
                if (currentUser?.role === 'admin') return <Dashboard onNavigate={handleNavigate} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                if (currentUser?.role === 'student') return <StudentDashboardPage student={currentUser.data} academy={academy!} feeCollections={feeCollections} batches={batches} onNavigate={handleNavigate} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                if (currentUser?.role === 'staff') return <StaffDashboardPage onNavigate={handleNavigate} academy={academy!} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                return null;

            case 'student-options': return <StudentOptionsPage onBack={handleGoBack} onNavigate={handleNavigate} isStaffView={currentUser?.role === 'staff'} onShowDevPopup={handleShowDevPopup} />;
            case 'active-students': return <ActiveStudentsPage onBack={handleGoBack} students={students} batches={batches} onToggleStudentStatus={handleToggleStudentStatus} onEditStudent={(id) => { setSelectedStudentId(id); handleNavigate('edit-student'); }} onViewStudent={(id) => { setSelectedStudentId(id); handleNavigate('student-details')}} initialFilter={studentListFilter} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined}/>;
            case 'inactive-students': return <InactiveStudentsPage onBack={handleGoBack} students={students} batches={batches} onToggleStudentStatus={handleToggleStudentStatus} />;
            case 'bulk-upload-students': return <BulkUploadPage onBack={handleGoBack} onSave={handleBulkSaveStudents} batches={batches} isDemoMode={isDemoMode || false} />;
            case 'new-student': return <NewStudentPage onBack={handleGoBack} onSave={async () => {}} batches={batches} academyId={academy?.academyId || ''} students={students} academy={academy!} />;
            case 'edit-student': return selectedStudentId ? <EditStudentPage onBack={handleGoBack} student={students.find(s => s.id === selectedStudentId)!} batches={batches} onUpdate={async () => {}} /> : null;
            case 'student-details':
                const currentStudent = students.find(s => s.id === selectedStudentId);
                if (!currentStudent) return <Dashboard onNavigate={handleNavigate} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                return <StudentDetailsPage onBack={handleGoBack} student={currentStudent} feeCollections={feeCollections.filter(f => f.studentId === currentStudent.id)} academyId={academyId} onSavePayment={async () => {}} transportRoutes={transportRoutes} onShowImage={setImageToView} academy={academy!} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} currentUserRole={currentUser?.role === 'admin' || currentUser?.role === 'staff' ? currentUser?.role : undefined} />;
            case 'birthday-list': return <BirthdayListPage onBack={handleGoBack} students={students} />;
            case 'registration-form-list': return <RegistrationFormListPage onBack={handleGoBack} students={students} onSelectStudent={(id) => { setSelectedStudentId(id); handleNavigate('registration-form-view'); }} />;
            case 'registration-form-view': return selectedStudentId ? <RegistrationFormViewPage onBack={handleGoBack} student={students.find(s => s.id === selectedStudentId)!} transportRoutes={transportRoutes} academy={academy!} /> : null;

            case 'batches': return <BatchesPage onBack={handleGoBack} onCreate={() => handleNavigate('new-batch')} batches={batches} onViewStudents={(filter) => { setStudentListFilter(filter); handleNavigate('active-students'); }} onEditBatch={(id) => { setSelectedBatchId(id); handleNavigate('edit-batch'); }} />;
            case 'new-batch': return <NewBatchPage onBack={handleGoBack} onSave={async () => {}} />;
            case 'edit-batch': return selectedBatchId ? <EditBatchPage onBack={handleGoBack} onSave={async () => {}} batch={batches.find(b => b.id === selectedBatchId)!} /> : null;

            case 'select-batch-attendance': return <SelectBatchForAttendancePage onBack={handleGoBack} batches={batches} onSelectBatch={(id) => { setSelectedBatchId(id); handleNavigate('take-attendance'); }} academyId={academyId} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'take-attendance': return selectedBatchId ? <TakeAttendancePage onBack={handleGoBack} batch={batches.find(b => b.id === selectedBatchId)!} students={students} academy={academy!} isDemoMode={isDemoMode} onShowImage={setImageToView} /> : null;

            case 'fees-options': return <FeesOptionsPage onBack={handleGoBack} onNavigate={handleNavigate} />;
            case 'fee-collection-report': return <FeeCollectionReportPage onBack={handleGoBack} feeCollections={feeCollections} onDelete={async () => {}} onUpdate={async () => {}} isDemoMode={isDemoMode} />;
            case 'fee-dues-list': return <FeeDuesListPage onBack={handleGoBack} students={students} batches={batches} feeCollections={feeCollections} academy={academy!} />;
            case 'select-batch-for-fees': return <SelectBatchForFeesPage onBack={handleGoBack} batches={batches} onSelectBatch={(id) => { setSelectedBatchId(id); handleNavigate('select-student-for-fees'); }} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'select-student-for-fees': return selectedBatchId ? <SelectStudentForFeesPage onBack={handleGoBack} batch={batches.find(b => b.id === selectedBatchId)!} students={students} onSelectStudent={(id) => { setSelectedStudentId(id); handleNavigate('student-fee-details'); }} /> : null;
            case 'student-fee-details': return selectedStudentId ? <StudentFeeDetailsPage onBack={handleGoBack} student={students.find(s => s.id === selectedStudentId)!} feeCollections={feeCollections.filter(f => f.studentId === selectedStudentId)} onSavePayment={async () => {}} academy={academy!} /> : null;

            case 'schedule-classes': return <ScheduleClassesPage onBack={handleGoBack} batches={batches} staff={staff} academyId={academyId} onSave={handleSaveSchedule} isDemoMode={isDemoMode} />;

            case 'income-expenses': return <IncomeExpensesPage onBack={handleGoBack} transactions={transactions} isDemoMode={isDemoMode} onSave={async () => {}} onUpdate={async () => {}} onDelete={async () => {}} />;

            case 'manage-exams': return <ManageExamsPage onBack={handleGoBack} exams={exams} onNavigate={handleNavigate} onPublish={async () => {}} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'create-exam': return <CreateExamPage onBack={handleGoBack} onSave={async () => {}} batches={batches} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;
            case 'record-marks': return pageParams.examId ? <RecordMarksPage onBack={handleGoBack} exam={exams.find(e => e.id === pageParams.examId)!} students={students} academy={academy!} isDemoMode={isDemoMode} onPublish={async () => {}} /> : null;

            case 'staff-options': return <StaffOptionsPage onBack={handleGoBack} onNavigate={handleNavigate} />;
            case 'staff-manager': return <StaffManagerPage onBack={handleGoBack} staff={staff} onManageAccess={(id) => { setSelectedStaffId(id); handleNavigate('staff-batch-access'); }} onToggleStatus={async () => {}} onShowDevPopup={handleShowDevPopup} />;
            case 'new-staff': return <NewStaffPage onBack={handleGoBack} onSave={async () => {}} staff={staff} />;
            case 'inactive-staff': return <InactiveStaffPage onBack={handleGoBack} staff={staff} onToggleStatus={async () => {}} />;
            case 'staff-batch-access': return selectedStaffId ? <StaffBatchAccessPage onBack={handleGoBack} staff={staff.find(s => s.id === selectedStaffId)!} batches={batches} onSave={async () => {}} /> : null;
            case 'mark-staff-attendance': return <MarkStaffAttendancePage onBack={handleGoBack} batches={batches} staff={staff} academyId={academyId} isDemoMode={isDemoMode} staffAttendance={staffAttendance} onSave={async () => {}} onDelete={async () => {}} />;
            case 'staff-attendance-report': return <StaffAttendanceReportPage onBack={handleGoBack} staff={staff} staffAttendance={staffAttendance} />;
            case 'manage-salaries': return <ManageSalariesPage onBack={handleGoBack} staff={staff} salaryPayments={salaryPayments} onSave={async () => {}} onDelete={async () => {}} isDemoMode={isDemoMode} />;

            case 'reports-options': return <ReportsPage onBack={handleGoBack} onNavigate={handleNavigate} onShowDevPopup={handleShowDevPopup} />;
            case 'attendance-report': return <AttendanceReportPage onBack={handleGoBack} batches={batches} students={students} academyId={academyId} academy={academy!} />;
            case 'study-material': return <StudyMaterialPage onBack={handleGoBack} materials={studyMaterials} batches={batches} onNavigate={handleNavigate} onDelete={async () => {}} />;
            case 'upload-study-material': return <UploadStudyMaterialPage onBack={handleGoBack} onSave={async () => {}} batches={batches} academyId={academyId} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser?.data.name || ''} isDemoMode={isDemoMode} />;
            case 'homework': return <HomeworkPage onBack={handleGoBack} homework={homework} batches={batches} onNavigate={handleNavigate} onDelete={async () => {}} />;
            case 'assign-homework': return <AssignHomeworkPage onBack={handleGoBack} onSave={async () => {}} batches={batches} academyId={academyId} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser?.data.name || ''} isDemoMode={isDemoMode} />;
            case 'manage-quizzes': return <ManageQuizzesPage onBack={handleGoBack} quizzes={quizzes} onNavigate={handleNavigate} onDelete={async () => {}} onShowDevPopup={handleShowDevPopup} />;
            case 'create-quiz': return <CreateQuizPage onBack={handleGoBack} onSave={async () => {}} batches={batches} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;

            case 'leave-manager': return <LeaveManagerPage onBack={handleGoBack} leaveRequests={leaveRequests} students={students} staff={staff} currentUser={currentUser!} batches={batches} onUpdateStatus={async () => {}} />;
            case 'todo-task': return <TodoTaskPage onBack={handleGoBack} tasks={tasks} staff={staff} onSaveTask={async () => {}} onToggleTaskStatus={async () => {}} onDeleteTask={async () => {}} isDemoMode={isDemoMode} />;
            case 'notice-board': return <NoticeBoardPage onBack={handleGoBack} notices={notices} onSaveNotice={async () => {}} onDeleteNotice={async () => {}} isDemoMode={isDemoMode} academyId={academyId} />;
            case 'transport-options': return <TransportOptionsPage onBack={handleGoBack} onCreate={() => handleNavigate('new-transport-route')} routes={transportRoutes} onNavigate={handleNavigate} onDelete={async () => {}} />;
            case 'settings': return <SettingsPage onBack={handleGoBack} onNavigate={handleNavigate} onShowDevPopup={handleShowDevPopup} />;
            case 'custom-sms-settings': return <CustomSmsSettingsPage onBack={handleGoBack} academy={academy!} onSave={async () => {}} />;
            case 'notifications': return <NotificationsPage onBack={handleGoBack} enquiries={enquiries.filter(e => e.status === 'New')} leaveRequests={leaveRequests.filter(l => l.status === 'Pending')} unmarkedAttendanceBatches={[]} scheduleAlerts={[]} onNavigate={handleNavigate} />;
            case 'legal': return <LegalPage onBack={handleGoBack} />;
            case 'my-account': return <MyAccountPage onBack={handleGoBack} onSave={async () => {}} onLogout={handleLogout} academy={academy!} />;
            case 'subscription': return <SubscriptionPage onBack={handleGoBack} academy={academy!} onSubscribe={async () => {}} />;

            default:
                if (currentUser?.role === 'admin') return <Dashboard onNavigate={handleNavigate} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                if (currentUser?.role === 'student') return <StudentDashboardPage student={currentUser.data} academy={academy!} feeCollections={feeCollections} batches={batches} onNavigate={handleNavigate} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                if (currentUser?.role === 'staff') return <StaffDashboardPage onNavigate={handleNavigate} academy={academy!} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                return null;
        }
    };

    const MainLayout: React.FC<{ children: React.ReactNode }> = ({ children }) => (
        <div className={`min-h-screen font-sans ${theme} bg-gray-100 dark:bg-gray-900 overflow-hidden flex flex-col`}>
            {isPlaceholderConfig && page !== 'onboarding' && <ConfigurationWarning />}
            {connectionError && <ConnectionErrorBanner message={connectionError} onClose={() => setConnectionError(null)} />}
            {isOffline && <OfflineIndicator />}
            <div className="flex-grow overflow-y-auto safe-top safe-bottom">
            {currentUser?.role === 'admin' && academy && (
                 <>
                     {page === 'dashboard' && <Header academy={academy} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={handleNavigate} notificationCount={0} />}
                     <SideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={handleNavigate} onLogout={handleLogout} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                     <div className={page === 'dashboard' ? "pb-20" : ""}>{children}</div>
                     {page === 'dashboard' && <BottomNav onNavigate={handleNavigate} activePage={page} onOpenChatbot={() => setIsChatbotOpen(true)} />}
                 </>
            )}
            {currentUser?.role === 'student' && academy && (
                <>
                    <StudentSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={handleNavigate} onLogout={handleLogout} systemLogoUrl={systemLogoUrl} />
                    <div>{children}</div>
                </>
            )}
            {currentUser?.role === 'staff' && academy && (
                <>
                    {page === 'dashboard' && <StaffHeader staffName={currentUser.data.name} academyName={academy.name} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={handleNavigate} notificationCount={0} />}
                    <StaffSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={handleNavigate} onLogout={handleLogout} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                    <div>{children}</div>
                </>
            )}
            </div>
            {showDevPopup && <DevInProgressPopup featureName={showDevPopup} onClose={() => setShowDevPopup(null)} />}
            {imageToView && <FullScreenImageViewer src={imageToView} alt="Full screen view" onClose={() => setImageToView(null)} />}
             {isChatbotOpen && academy && (
                <AIChatbot isOpen={isChatbotOpen} onClose={() => setIsChatbotOpen(false)} onNavigate={(p) => { handleNavigate(p); setIsChatbotOpen(false); }} students={students} feeCollections={feeCollections} batches={batches} academyId={academy.id} />
            )}
        </div>
    );

    if (isLoading) return <SplashScreen />;
    if (!currentUser) return (
        <div className="min-h-screen flex flex-col safe-top safe-bottom">
            {isPlaceholderConfig && <ConfigurationWarning />}
            {page === 'onboarding' && <OnboardingPage onComplete={() => { localStorage.setItem('onboardingCompleted', 'true'); setPage('role-selection'); }} />}
            {page === 'role-selection' && <RoleSelectionPage onSelectRole={(role) => { localStorage.setItem('lastSelectedRole', role); setLoginPageRole(role); handleNavigate('login'); }} onBack={() => {}} />}
            {page === 'register' && <RegisterPage onNavigateToLogin={() => handleNavigate('login')} />}
            {page === 'complete-registration' && <CompleteRegistrationPage onComplete={async () => {}} onLogout={handleLogout} userEmail={auth.currentUser?.email || ''} externalError={authError} clearExternalError={() => setAuthError(null)} />}
            {page !== 'onboarding' && page !== 'role-selection' && page !== 'register' && page !== 'complete-registration' &&
                <LoginPage onLogin={handleLogin} onNavigateToRegister={() => handleNavigate('register')} externalError={authError} clearExternalError={() => setAuthError(null)} initialRole={loginPageRole} onGoBack={() => { localStorage.removeItem('lastSelectedRole'); setPage('role-selection'); }} systemLogoUrl={systemLogoUrl} />
            }
        </div>
    );

    return <MainLayout>{renderPage()}</MainLayout>;
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  SafeAreaView, 
  StatusBar, 
  TouchableOpacity, 
  ScrollView, 
  Alert,
  KeyboardAvoidingView,
  Platform,
  Dimensions
} from 'react-native';

// Firebase (Assuming standard React Native Firebase library setup)
import auth from '@react-native-firebase/auth';
import firestore from '@react-native-firebase/firestore';

// Core Components (Native Versions)
import { NativeHeader } from './components/native/NativeHeader';
import { NativeDashboard } from './components/native/NativeDashboard';
import { NativeTakeAttendance } from './components/native/NativeTakeAttendance';
import { NativeSubscription } from './components/native/NativeSubscription';

const { width } = Dimensions.get('window');

export default function App() {
    const [page, setPage] = useState('dashboard');
    const [user, setUser] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [theme, setTheme] = useState('light');

    // Navigation Stack for Native Back Handling
    const [history, setHistory] = useState(['dashboard']);

    useEffect(() => {
        const subscriber = auth().onAuthStateChanged((userState) => {
            setUser(userState);
            if (isLoading) setIsLoading(false);
        });
        return subscriber;
    }, []);

    const handleNavigate = useCallback((newPage: string) => {
        setHistory(prev => [...prev, newPage]);
        setPage(newPage);
    }, []);

    const handleBack = useCallback(() => {
        if (history.length > 1) {
            const newHistory = [...history];
            newHistory.pop();
            const prev = newHistory[newHistory.length - 1];
            setHistory(newHistory);
            setPage(prev);
        } else {
            setPage('dashboard');
        }
    }, [history]);

    if (isLoading) {
        return (
            <View style={styles.center}>
                <Text>Loading OptiLearn...</Text>
            </View>
        );
    }

    const renderPage = () => {
        switch (page) {
            case 'dashboard':
                return <NativeDashboard onNavigate={handleNavigate} />;
            case 'take-attendance':
                return <NativeTakeAttendance onBack={handleBack} />;
            case 'subscription':
                return <NativeSubscription onBack={handleBack} />;
            default:
                return <NativeDashboard onNavigate={handleNavigate} />;
        }
    };

    return (
        <SafeAreaView style={[styles.container, theme === 'dark' ? styles.darkBg : styles.lightBg]}>
            <StatusBar barStyle={theme === 'dark' ? 'light-content' : 'dark-content'} />
            <KeyboardAvoidingView 
                behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
                style={styles.flex}
            >
                <NativeHeader 
                    onMenuPress={() => Alert.alert("Menu", "Drawer coming soon")}
                    onThemeToggle={() => setTheme(theme === 'light' ? 'dark' : 'light')}
                />

                <View style={styles.flex}>
                    {renderPage()}
                </View>

                {page === 'dashboard' && (
                    <View style={styles.bottomNav}>
                        <TouchableOpacity onPress={() => handleNavigate('dashboard')} style={styles.navItem}>
                            <Text style={styles.navText}>Home</Text>
                        </TouchableOpacity>
                        <TouchableOpacity onPress={() => handleNavigate('subscription')} style={styles.navItem}>
                            <Text style={styles.navText}>Billing</Text>
                        </TouchableOpacity>
                    </View>
                )}
            </KeyboardAvoidingView>
        </SafeAreaView>
    );
}

