import React, { useState } from 'react';
import { 
  View, 
  Text, 
  TouchableOpacity, 
  StyleSheet, 
  LayoutAnimation, 
  Platform, 
  UIManager 
} from 'react-native';

// Enable LayoutAnimation on Android
if (Platform.OS === 'android' && UIManager.setLayoutAnimationEnabledExperimental) {
  UIManager.setLayoutAnimationEnabledExperimental(true);
}

interface Option {
  label: string;
  value: string;
}

interface NativeDropdownProps {
  label?: string;
  options: Option[];
  selectedValue: string | null;
  onSelect: (value: string) => void;
  placeholder?: string;
}

export const NativeDropdown: React.FC<NativeDropdownProps> = ({ 
  label, 
  options, 
  selectedValue, 
  onSelect, 
  placeholder = "Select Option" 
}) => {
  const [isOpen, setIsOpen] = useState(false);

  const toggleDropdown = () => {
    LayoutAnimation.configureNext(LayoutAnimation.Presets.easeInEaseOut);
    setIsOpen(!isOpen);
  };

  const handleSelect = (value: string) => {
    onSelect(value);
    toggleDropdown();
  };

  const currentLabel = options.find(o => o.value === selectedValue)?.label || placeholder;

  return (
    <View style={styles.container}>
      {label && <Text style={styles.label}>{label}</Text>}

      <TouchableOpacity 
        onPress={toggleDropdown} 
        style={[styles.trigger, isOpen && styles.triggerOpen]}
        activeOpacity={0.7}
      >
        <Text style={[styles.triggerText, !selectedValue && styles.placeholderText]}>
          {currentLabel}
        </Text>
        <Text style={styles.chevron}>{isOpen ? '▲' : '▼'}</Text>
      </TouchableOpacity>

      {isOpen && (
        <View style={styles.optionsContainer}>
          {options.map((option) => (
            <TouchableOpacity
              key={option.value}
              onPress={() => handleSelect(option.value)}
              style={[
                styles.option,
                selectedValue === option.value && styles.optionSelected
              ]}
            >
              <Text style={[
                styles.optionText,
                selectedValue === option.value && styles.optionTextSelected
              ]}>
                {option.label}
              </Text>
              {selectedValue === option.value && <Text style={styles.check}>✓</Text>}
            </TouchableOpacity>
          ))}
        </View>
      )}
    </View>
  );
};

